INSERT INTO auction
item_id, seller_id, winner_id, type, inspection_yn, status, start_price, bid_unit, vickrey_price, bid_count, buy_now_price, wish_count, start_date, end_date, cancel_date, winner_price, created_at
#{itemId}, #{sellerId}, #{winnerId}, #{type}, #{inspectionYn}, #{status}, #{startPrice}, #{bidUnit}, #{vickreyPrice}, #{bidCount}, #{buyNowPrice}, #{wishCount}, #{startDate}, #{endDate}, #{cancelDate}, #{winnerPrice}, #{createdAt}

mapper.select:
SELECT a.id AS auction_id, ai.id AS item_id, ai.brand, ai.name, a.status, a.start_price, a.buy_now_price, a.bid_count, a.wish_count, a.end_date, ii.url AS representative_image_url, a.created_at FROM auction a INNER JOIN auction_item ai ON a.item_id = ai.id LEFT JOIN item_image ii ON ii.item_id = ai.id AND ii.display_order = ( SELECT MIN(ii2.display_order) FROM item_image ii2 WHERE ii2.item_id = ai.id ) WHERE 1 = 1
AND a.status = #{status}
AND a.seller_id = #{sellerId}
AND ai.category_id = #{categoryId}
ORDER BY
a.wish_count ${order}, a.created_at DESC a.created_at ${order}

SELECT COUNT(*)
FROM auction a
INNER JOIN auction_item ai ON a.item_id = ai.id
WHERE 1 = 1

    AND a.status = #{status}


    AND a.seller_id = #{sellerId}


    AND ai.category_id = #{categoryId}

